          {/* Past mock interview sessions */}
          {mockPastSessions.length > 0 && (
            <div>
              <h3 className="font-semibold text-sm mb-3 flex items-center gap-2">
                <History className="h-4 w-4 text-muted-foreground" /> Past Mock Interviews
