            <div ref={chatEndRef} />
          </div>

          {/* Controls */}
          <div className="flex items-center justify-center gap-3 py-2">
            {/* Mic button */}
            {!candidateRecording && !aiSpeaking && !voiceProcessing ? (
              <Button
                onClick={startVoiceRecording}
                size="lg"
