    stopVoiceMode()
    stopMockCamera()
    stopMockFrameCapture()
    mockFramesRef.current = []
    setMockLiveTranscript('')
    setMockSession(null)
    setMockFeedback(null)
    setMockResponseText('')
    setMockTargetRole('')
    setMockJobDescription('')
    setMockShowSetup(false)
    setShowTranscript(false)
    setVoiceMode(false)
    voiceModeRef.current = false
